     9→
    10→/// A mixin class for paging notifiers.
    11→///
    12→/// This mixin provides a method to fetch data from a repository and
    13→/// a method to load the next page of data.
    14→///
    15→/// The [fetch] method is used to fetch data from a repository.
    16→/// The [loadNext] method is used to load the next page of data.
    17→///
    18→/// See also: https://zenn.dev/yumemi_inc/articles/4323e9732fb771
    19→mixin PagePagingNotifierMixin<T> on AsyncNotifier<PagingData<T>> {
    20→  static const int initialPage = 0;
    21→  static const int defaultPageSize = 100;
    22→
    23→  Future<PagingData<T>> fetch({required int page, required int pageSize});
    24→
    25→  @override
    26→  Future<PagingData<T>> build() =>
    27→      fetch(page: initialPage, pageSize: defaultPageSize);
    28→
    29→  Future<void> loadNext({int? pageSize}) async {
    30→    final value = state.valueOrNull;
    31→    if (value == null || state.hasError || !value.hasMore) return;
    32→
    33→    state = AsyncLoading<PagingData<T>>().copyWithPrevious(state);
    34→
    35→    state = await state.guardPreservingPreviousOnError(() async {
    36→      final nextPage = value.page + 1;
    37→      final next =
    38→          await fetch(page: nextPage, pageSize: pageSize ?? defaultPageSize);
    39→      return value.copyWith(
    40→        items: [...value.items, ...next.items],
    41→        page: nextPage,
    42→        hasMore: next.hasMore,
