// Package imports:

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/paging_data.dart';

/// A mixin class for paging notifiers.
///
/// This mixin provides a method to fetch data from a repository and
/// a method to load the next page of data.
///
/// The [fetch] method is used to fetch data from a repository.
/// The [loadNext] method is used to load the next page of data.
///
/// See also: https://zenn.dev/yumemi_inc/articles/4323e9732fb771
mixin PagePagingNotifierMixin<T> on AsyncNotifier<PagingData<T>> {
  static const int initialPage = 0;
  static const int defaultPageSize = 100;

  Future<PagingData<T>> fetch({required int page, required int pageSize});

  @override
  Future<PagingData<T>> build() =>
      fetch(page: initialPage, pageSize: defaultPageSize);

  Future<void> loadNext({int? pageSize}) async {
    final value = state.valueOrNull;
    if (value == null || state.hasError || !value.hasMore) return;

    state = AsyncLoading<PagingData<T>>().copyWithPrevious(state);

    state = await state.guardPreservingPreviousOnError(() async {
      final nextPage = value.page + 1;
      final next =
          await fetch(page: nextPage, pageSize: pageSize ?? defaultPageSize);
      return value.copyWith(
        items: [...value.items, ...next.items],
        page: nextPage,
        hasMore: next.hasMore,
        total: next.total,
      );
    });
  }

  void forceRefresh() {
    state = AsyncLoading<PagingData<T>>();
    ref.invalidateSelf();
  }
}

mixin AutoDisposePagePagingNotifierMixin<T>
    on AutoDisposeAsyncNotifier<PagingData<T>> {
  static const int initialPage = 0;
  static const int defaultPageSize = 100;

  Future<PagingData<T>> fetch({required int page, required int pageSize});

  @override
  Future<PagingData<T>> build() =>
      fetch(page: initialPage, pageSize: defaultPageSize);

  Future<void> loadNext({int? pageSize}) async {
    final value = state.valueOrNull;
    if (value == null || state.hasError || !value.hasMore) return;

    state = AsyncLoading<PagingData<T>>().copyWithPrevious(state);

    state = await state.guardPreservingPreviousOnError(() async {
      final nextPage = value.page + 1;
      final next =
          await fetch(page: nextPage, pageSize: pageSize ?? defaultPageSize);
      return value.copyWith(
        items: [...value.items, ...next.items],
        page: nextPage,
        hasMore: next.hasMore,
        total: next.total,
      );
    });
  }

  void forceRefresh() {
    state = AsyncLoading<PagingData<T>>();
    ref.invalidateSelf();
  }
}

extension AsyncValueExt<T> on AsyncValue<T> {
  Future<AsyncValue<T>> guardPreservingPreviousOnError(
    Future<T> Function() future,
  ) async {
    try {
      return AsyncValue.data(await future());
    } on Exception catch (err, stack) {
      return AsyncValue.error(err, stack);
    }
  }
}

